mapper.update:
UPDATE catalog_sync_task
SET status = #{pendingStatus},
    failure_reason = #{failureReason},
    updated_at = #{now}
WHERE snapshot_id = #{snapshotId}
  AND status = #{processingStatus}

UPDATE catalog_sync_task
SET status = #{succeededStatus},
    failure_reason = NULL,
    succeeded_once = 1,
    updated_at = #{now}
WHERE id = #{id}

UPDATE catalog_sync_task
SET status = #{status},
    failure_reason = #{failureReason},
    updated_at = #{now}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM catalog_sync_task
WHERE snapshot_id = #{snapshotId}

SELECT COUNT(*)
FROM catalog_sync_task
WHERE snapshot_id = #{snapshotId}
  AND status = #{status}

SELECT goods_id
FROM catalog_sync_task
WHERE snapshot_id = #{snapshotId}
  AND status IN (#{succeededStatus}, #{skippedStatus})
  AND last_attempt_at IS NOT NULL
  AND last_attempt_at >= #{attemptedAfter}
